mapper.update:
update collaborative_document
set title = #{title},
    content = #{content},
    latest_revision = #{nextRevision},
    updated_by = #{updatedBy},
    updated_at = #{updatedAt},
    lock_version = lock_version + 1
where id = #{id}
  and lock_version = #{expectedVersion}
  and latest_revision = #{expectedRevision}
